class Solution:
    def countPathsWithXorValue(self, grid, k):
        MOD = 10 ** 9 + 7
        m, n = len(grid), len(grid[0])
        total = 0
        def dfs(i, j, x):
            nonlocal total
            x ^= grid[i][j]
            if i == m - 1 and j == n - 1:
                if x == k:
                    total += 1
                return
            if i + 1 < m:
                dfs(i + 1, j, x)
            if j + 1 < n:
                dfs(i, j + 1, x)
        dfs(0, 0, 0)
        return total % MOD

