class Solution:
    def countPathsWithXorValue(self, grid, k):
        MOD = 10 ** 9 + 7
        m, n = len(grid), len(grid[0])
        dp = [[[0] * 16 for _ in range(n)] for _ in range(m)]
        dp[0][0][grid[0][0]] = 1
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                cell = dp[i][j]
                if i > 0:
                    for x in range(16):
                        c = dp[i - 1][j][x]
                        if c:
                            cell[x ^ grid[i][j]] = (cell[x ^ grid[i][j]] + c) % MOD
                if j > 0:
                    for x in range(16):
                        c = dp[i][j - 1][x]
                        if c:
                            cell[x ^ grid[i][j]] = (cell[x ^ grid[i][j]] + c) % MOD
        return dp[m - 1][n - 1][k] % MOD

solutions.javascript:
var countPathsWithXorValue = function(grid, k) {
    const MOD = 1000000007;
    const m = grid.length, n = grid[0].length;
    const dp = Array.from({ length: m }, () => Array.from({ length: n }, () => new Array(16).fill(0)));
    dp[0][0][grid[0][0]] = 1;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i === 0 && j === 0) continue;
            const cell = dp[i][j];
            if (i > 0) {
                const above = dp[i - 1][j];
                for (let x = 0; x < 16; x++) {
                    const c = above[x];
                    if (c) {
                        const t = x ^ grid[i][j];
                        cell[t] = (cell[t] + c) % MOD;
                    }
                }
            }
            if (j > 0) {
                const left = dp[i][j - 1];
                for (let x = 0; x < 16; x++) {
                    const c = left[x];
                    if (c) {
                        const t = x ^ grid[i][j];
                        cell[t] = (cell[t] + c) % MOD;
                    }
                }
            }
        }
    }
    return dp[m - 1][n - 1][k] % MOD;
};
